        if (!Number.isFinite(p.lat) || !Number.isFinite(p.lon)) return null;
        return { lat: p.lat, lon: p.lon, timestamp: p.timestamp != null ? p.timestamp : null };
    }
    const m = pos(ts.missionStartPosition);
    if (!m) return null;
    const r = pos(ts.returnPosition);
    const ret = r || { lat: m.lat, lon: m.lon, timestamp: m.timestamp };
    return {
        active: !!ts.active,
        trackingSessionId: ts.trackingSessionId != null ? ts.trackingSessionId : null,
        missionStartPosition: m,
        returnPosition: ret
